void oled_render_splash(void) {
    oled_write_raw_P(splash_logo, sizeof(splash_logo));
}

static bool     splash_done = false;
static uint32_t splash_timer = 0;

// Call this from oled_task_user or candypad_render_default_user
bool candypad_render_default_user(void) {
    if (!splash_done) {
        if (splash_timer == 0) {
            splash_timer = timer_read32();
            oled_render_splash();
        }
        if (timer_elapsed32(splash_timer) > 750) {
            splash_done = true;
            oled_clear();
        }
        return true; // Block default rendering during splash
    }
    return false; // Let default rendering proceed
}

